// NODE: Select Concept
// Weighted random concept pick + vibe + appStyle + gender selection
// Mode: Run Once for All Items

const concepts = $input.all().map(item => item.json);

if (concepts.length === 0) {
  throw new Error('No active concepts found in Airtable');
}

// --- Weighted random selection ---
function weightedRandom(items, weightField) {
  const totalWeight = items.reduce((sum, item) => sum + (Number(item[weightField]) || 1), 0);
  let random = Math.random() * totalWeight;
  for (const item of items) {
    random -= (Number(item[weightField]) || 1);
    if (random <= 0) return item;
  }
  return items[items.length - 1];
}

const concept = weightedRandom(concepts, 'weight');

// --- Vibe selection (toxic only â most viral) ---
function pickVibe() {
  return 'toxic';
}

// --- App style (iMessage only for now) ---
function pickAppStyle() {
  return 'imessage';
}

// --- Gender: ALWAYS male (girl analyzes a guy) ---
const personGender = 'male';

// Use forced_vibe from Airtable if set, otherwise random
const vibe = concept.forced_vibe || pickVibe();
const appStyle = pickAppStyle();
const scenarioName = vibe + '-' + concept.concept_id + '-' + Date.now();

// Body clip count from Airtable (default 3, min 2, max 5)
const bodyClipCount = Math.min(5, Math.max(2, Number(concept.body_clip_count) || 3));

return [{
  json: {
    concept,
    vibe,
    appStyle,
    personGender,
    scenarioName,
    conceptId: concept.concept_id,
    bodyClipCount
  }
}];

// NODE: Validate Scenario
// Parses Gemini response and validates the ContentScenario JSON
// Mode: Run Once for All Items

// Basic LLM Chain outputs { text: "..." } with the raw LLM response
const llmOutput = $input.first().json;
const { vibe } = $('Select Concept').first().json;
const { randomRelStatus, randomName } = $('Build Scenario Prompt').first().json;

// --- JSON Repair utility ---
function repairJson(raw) {
  let s = raw;

  // 1. Strip markdown code fences
  s = s.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  // Replace smart/curly quotes with straight quotes
  s = s.replace(/[\u201C\u201D]/g, '"').replace(/[\u2018\u2019]/g, "'");

  // 2. Extract JSON object if there's text before/after it
  const firstBrace = s.indexOf('{');
  const lastBrace = s.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace > firstBrace) {
    s = s.substring(firstBrace, lastBrace + 1);
  }

  // 3. Remove control characters
  s = s.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');

  // 4. Smart quote repair: walk through and escape internal quotes
  // When we see a " inside a string, peek ahead — if the next non-whitespace
  // char is NOT valid JSON continuation (, } ] :), it's an internal quote
  let result = '';
  let inString = false;
  let escaped = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (escaped) { result += ch; escaped = false; continue; }
    if (ch === '\\') { result += ch; escaped = true; continue; }
    if (ch === '"') {
      if (!inString) {
        inString = true;
        result += ch;
      } else {
        // Peek ahead: skip whitespace/newlines to find next meaningful char
        let peekIdx = i + 1;
        while (peekIdx < s.length && /[\s\r\n]/.test(s[peekIdx])) peekIdx++;
        const nextChar = peekIdx < s.length ? s[peekIdx] : '';
        // Valid JSON after closing a string value: , } ] : or EOF
        if (nextChar === ',' || nextChar === '}' || nextChar === ']' || nextChar === ':' || nextChar === '') {
          inString = false;
          result += ch;
        } else {
          // Internal quote — escape it
          result += '\\"';
        }
      }
      continue;
    }
    if (inString && ch === '\n') { result += '\\n'; continue; }
    if (inString && ch === '\r') { continue; }
    result += ch;
  }
  s = result;

  // 5. Fix trailing commas before } or ]
  s = s.replace(/,\s*([\]}])/g, '$1');

  return s;
}

// Extract JSON from LLM output
// The output parser may have already parsed it into an object
let scenario;
try {
  const raw = llmOutput.output || llmOutput.text || llmOutput;

  if (typeof raw === 'object' && raw !== null) {
    // Already parsed by Structured Output Parser
    scenario = raw;
  } else {
    // Raw string — parse with repair
    const repaired = repairJson(String(raw));
    scenario = JSON.parse(repaired);
  }
} catch (e1) {
  try {
    const raw = llmOutput.output || llmOutput.text || llmOutput;
    let repaired = repairJson(String(raw));
    repaired = repaired.replace(/[\u201C\u201D\u2018\u2019]/g, '"');
    const posMatch = e1.message.match(/position (\d+)/);
    if (posMatch) {
      const pos = parseInt(posMatch[1]);
      repaired = repaired.substring(0, pos) + '\\' + repaired.substring(pos);
    }
    scenario = JSON.parse(repaired);
  } catch (e2) {
    return [{ json: { valid: false, errors: ['JSON parse failed after repair: ' + e1.message], scenario: null } }];
  }
}

const errors = [];

// --- Required top-level fields ---
if (!scenario.id) errors.push('Missing id');
if (!scenario.chat) errors.push('Missing chat');
if (!scenario.results) errors.push('Missing results');

if (scenario.chat) {
  if (!scenario.chat.contactName) errors.push('Missing chat.contactName');
  if (!['imessage', 'instagram', 'whatsapp'].includes(scenario.chat.appStyle)) {
    errors.push('Invalid appStyle: ' + scenario.chat.appStyle);
  }
  if (!Array.isArray(scenario.chat.messages) || scenario.chat.messages.length < 12) {
    errors.push('Too few messages: ' + (scenario.chat.messages ? scenario.chat.messages.length : 0) + ' (min 12)');
  }
  if (scenario.chat.messages && scenario.chat.messages.length > 25) {
    errors.push('Too many messages: ' + scenario.chat.messages.length + ' (max 25)');
  }
  // Validate each message
  if (scenario.chat.messages) {
    scenario.chat.messages.forEach((msg, i) => {
      if (!['them', 'me'].includes(msg.sender)) errors.push('Message ' + i + ': invalid sender "' + msg.sender + '"');
      if (!msg.text || typeof msg.text !== 'string') errors.push('Message ' + i + ': missing or invalid text');
    });

    // --- Chat toxicity check: "them" messages must contain actual conflict/tension ---
    const theirMessages = scenario.chat.messages.filter(m => m.sender === 'them').map(m => m.text.toLowerCase());
    const allTheirText = theirMessages.join(' ');
    const TOXIC_INDICATORS = [
      'dramatic', 'chill', 'relax', 'calm down', 'whatever', 'idc', 'i don\'t care',
      'why does it matter', 'big deal', 'overreact', 'insecure', 'crazy', 'psycho',
      'it\'s not like that', 'just a friend', 'you always', 'k', 'fine', 'i never said',
      'that\'s not what', 'leave me alone', 'i don\'t have time', 'i was busy',
      'stop', 'enough', 'you\'re tripping', 'not my problem', 'lol ok', 'bye',
      'who cares', 'get over it', '...', 'nah', 'smh', 'bro', 'dude'
    ];
    const toxicHits = TOXIC_INDICATORS.filter(t => allTheirText.includes(t));
    if (toxicHits.length < 2) {
      errors.push('Chat lacks toxicity: "them" messages contain only ' + toxicHits.length + ' toxic indicators (need 2+). Chat may be too boring/normal.');
    }
  }

  // --- Relationship status coherence check ---
  // The chat MUST contain explicit phrases that match the assigned relationship status.
  // Without these, a viewer can't tell the status from the chat alone.
  if (randomRelStatus && scenario.chat.messages) {
    const allChatText = scenario.chat.messages.map(m => m.text.toLowerCase()).join(' ');

    const STATUS_KEYWORDS = {
      'ex': [
        'broke up', 'breakup', 'break up', 'broken up',
        'when we were together', 'when we were dating',
        'my ex', 'you\'re my ex', 'youre my ex',
        'we ended', 'after we split', 'since we split',
        'not together anymore', 'we\'re done', 'were done',
        'already moved on', 'moved on',
        'after everything we had',
        'we\'re not together', 'were not together',
        'after the breakup', 'since the breakup',
      ],
      'boyfriend': [
        'my boyfriend', 'my bf', 'your girlfriend', 'your gf',
        'you\'re my boyfriend', 'youre my boyfriend',
        'as your girlfriend', 'as your gf',
        'i\'m your girlfriend', 'im your girlfriend',
        'we\'ve been together', 'weve been together', 'been together for',
        'in this relationship', 'our relationship',
        'we\'re dating', 'were dating', 'we are dating',
        'our anniversary', 'dating for',
      ],
      'crush': [
        'i like you', 'i liked you', 'i\'ve liked', 'ive liked',
        'catch feelings', 'caught feelings', 'catching feelings',
        'just friends', 'friend zone', 'friendzone',
        'do you like me', 'does he like', 'do you like',
        'my crush', 'have a crush', 'had a crush',
        'are we just friends', 'more than friends',
        'i didn\'t think you', 'into me',
        'feel the same', 'feelings for',
      ],
      'situationship': [
        'what are we', 'are we together', 'are we official',
        'not even official', 'not official',
        'won\'t commit', 'wont commit',
        'call me your girlfriend', 'your girlfriend but',
        'just having fun', 'just vibing',
        'we\'re not even together', 'not even dating',
        'labels', 'define this', 'define what we',
        'situationship',
        'like your girlfriend but',
        'girlfriend stuff', 'boyfriend privileges',
      ],
      'talking': [
        'we\'ve been talking', 'weve been talking', 'been talking for',
        'talking stage', 'talking for like',
        'just started talking', 'we just started',
        'barely know', 'i barely know you',
        'only been talking', 'only been texting',
        'just met', 'just got your number',
        'been texting for', 'texting for like',
        'just started texting',
      ],
    };

    const keywords = STATUS_KEYWORDS[randomRelStatus];
    if (keywords) {
      const statusHit = keywords.some(kw => allChatText.includes(kw));
      if (!statusHit) {
        errors.push('CRITICAL: Chat missing status anchor for "' + randomRelStatus + '". No keyword found that establishes the relationship status. The chat could be ANY status. Needs explicit reference like: ' + keywords.slice(0, 3).map(k => '"' + k + '"').join(', '));
      }
    }
  }
}

const r = scenario.results;
if (r) {
  // --- personName auto-fix ---
  const expectedName = r.personGender === 'male' ? 'Him' : 'Her';
  if (r.personName !== expectedName) {
    errors.push('personName should be "' + expectedName + '", got "' + r.personName + '" (auto-fixed)');
    r.personName = expectedName;
  }

  // --- Scores 0-100 ---
  const scoreFields = ['overallScore', 'warmthScore', 'communicationScore', 'dramaScore', 'distanceScore', 'passionScore'];
  scoreFields.forEach(field => {
    const val = r[field];
    if (typeof val !== 'number' || val < 0 || val > 100) {
      errors.push(field + ' out of range: ' + val);
    }
  });

  // --- Hard-code: toxic score must be 70+ (overallScore ≤ 30) for all vibes ---
  if (typeof r.overallScore === 'number' && r.overallScore > 30) {
    errors.push('overallScore=' + r.overallScore + ' too high (max 30, toxic score must be 70+) — auto-fixed to 30');
    r.overallScore = 30;
  }

  // --- Valid soul type IDs ---
  const MALE_SOUL_TYPES = [
    'male-untamable', 'male-gentle-flame', 'male-silent-abyss', 'male-faded-crown',
    'male-sweet-poison', 'male-wounded-prince', 'male-burning-promise', 'male-final-silence',
    'male-dark-mirror', 'male-ice-charmer', 'male-silent-choke', 'male-shifting-flame',
    'male-chameleon', 'male-star-collector'
  ];
  const FEMALE_SOUL_TYPES = [
    'female-love-rush', 'female-natural-state', 'female-fire-dance', 'female-frozen-bloom',
    'female-torn-silk', 'female-inner-voice', 'female-silent-venom', 'female-sunset-soul',
    'female-deep-shadow', 'female-wild-luxury', 'female-living-maze', 'female-golden-rule',
    'female-savage-grace', 'female-quiet-storm', 'female-rising-phoenix', 'female-liquid-mirror'
  ];
  const ALL_SOUL_TYPES = MALE_SOUL_TYPES.concat(FEMALE_SOUL_TYPES);

  if (!ALL_SOUL_TYPES.includes(r.personSoulType)) {
    errors.push('Invalid personSoulType: "' + r.personSoulType + '"');
  }
  if (!ALL_SOUL_TYPES.includes(r.userSoulType)) {
    errors.push('Invalid userSoulType: "' + r.userSoulType + '"');
  }

  // Gender-soul type cross check
  if (r.personGender === 'male' && r.personSoulType && !r.personSoulType.startsWith('male-')) {
    errors.push('personGender=male but personSoulType is not male: ' + r.personSoulType);
  }
  if (r.personGender === 'male' && r.userSoulType && !r.userSoulType.startsWith('female-')) {
    errors.push('personGender=male but userSoulType should be female: ' + r.userSoulType);
  }
  if (r.personGender === 'female' && r.personSoulType && !r.personSoulType.startsWith('female-')) {
    errors.push('personGender=female but personSoulType is not female: ' + r.personSoulType);
  }
  if (r.personGender === 'female' && r.userSoulType && !r.userSoulType.startsWith('male-')) {
    errors.push('personGender=female but userSoulType should be male: ' + r.userSoulType);
  }

  // --- Traits ---
  if (!Array.isArray(r.personTraits) || r.personTraits.length !== 5) {
    errors.push('personTraits must have exactly 5, got ' + (r.personTraits ? r.personTraits.length : 0));
  }
  if (!Array.isArray(r.userTraits) || r.userTraits.length !== 5) {
    errors.push('userTraits must have exactly 5, got ' + (r.userTraits ? r.userTraits.length : 0));
  }

  // Banned traits filter
  const BANNED = ['Early Stage', 'New Connection', 'Fresh Start', 'Getting to Know', 'Just Met', 'Beginning Phase'];
  const allTraits = (r.personTraits || []).concat(r.userTraits || []);
  allTraits.forEach(trait => {
    if (BANNED.some(b => trait.toLowerCase().includes(b.toLowerCase()))) {
      errors.push('Banned trait found: "' + trait + '"');
    }
  });

  // --- Categories ---
  const requiredCategories = ['intentions', 'chemistry', 'effort', 'redFlagsGreenFlags', 'trajectory'];
  requiredCategories.forEach(cat => {
    if (!r.categories || !r.categories[cat] || !r.categories[cat].description) {
      errors.push('Missing or empty category: ' + cat);
    }
  });

  // --- Message Insights ---
  if (!Array.isArray(r.messageInsights)) {
    errors.push('messageInsights is not an array');
  } else {
    if (r.messageInsights.length < 3 || r.messageInsights.length > 6) {
      errors.push('messageInsights count=' + r.messageInsights.length + ' (need 3-6)');
    }

    // Check each insight message is an exact quote from chat
    // Only "them" messages are valid for insights (we analyze the OTHER person, not the user)
    const chatTexts = (scenario.chat && scenario.chat.messages ? scenario.chat.messages : []).map(m => m.text);
    const theirChatTexts = (scenario.chat && scenario.chat.messages ? scenario.chat.messages : [])
      .filter(m => m.sender === 'them')
      .map(m => m.text);

    // First pass: try to match/fix each insight
    // STRICT matching: only exact match or case-insensitive exact match allowed.
    // Substring matching was removed because it let hallucinated messages slip through
    // by matching partial text fragments (e.g., hallucinated "why does it matter to you"
    // would match real message containing "does it matter").
    r.messageInsights.forEach((insight, i) => {
      // Step 1: Exact match against "them" messages (preferred)
      if (theirChatTexts.includes(insight.message)) {
        // Perfect match — keep as-is
      }
      // Step 2: Exact match against ALL messages (edge case: "me" message in DECODED context)
      else if (chatTexts.includes(insight.message)) {
        // Valid but not ideal — keep it
      }
      // Step 3: Case-insensitive exact match against "them" messages
      else {
        const insightLower = insight.message.trim().toLowerCase();
        let matched = theirChatTexts.find(t => t.trim().toLowerCase() === insightLower);
        // Step 4: Case-insensitive exact match against ALL messages
        if (!matched) {
          matched = chatTexts.find(t => t.trim().toLowerCase() === insightLower);
        }
        // Step 5: AI quoted part of a "them" message (forward substring only, min 20 chars)
        // The insight must be a substantial portion of the chat message (at least 50% length)
        if (!matched && insightLower.length >= 20) {
          matched = theirChatTexts.find(t => {
            const tLower = t.toLowerCase();
            return tLower.includes(insightLower) && insightLower.length >= tLower.length * 0.5;
          });
        }
        if (matched) {
          insight.message = matched; // Auto-fix to exact chat text
        } else {
          insight._hallucinated = true; // Mark for removal
          errors.push('Insight ' + i + ': HALLUCINATED message "' + insight.message + '" not in chat (auto-removed)');
        }
      }
      if (!['RED FLAG', 'GREEN FLAG', 'DECODED'].includes(insight.tag)) {
        errors.push('Insight ' + i + ': invalid tag "' + insight.tag + '"');
      }
    });

    // Remove hallucinated insights (messages the AI invented)
    const beforeHallucinationFilter = r.messageInsights.length;
    r.messageInsights = r.messageInsights.filter(ins => !ins._hallucinated);
    // Clean up temp flag
    r.messageInsights.forEach(ins => delete ins._hallucinated);
    if (beforeHallucinationFilter !== r.messageInsights.length) {
      const removed = beforeHallucinationFilter - r.messageInsights.length;
      errors.push('Removed ' + removed + ' hallucinated insight(s) with invented messages. ' + r.messageInsights.length + ' remaining.');
    }

    // If too few insights remain after filtering, it's a critical problem
    if (r.messageInsights.length < 3) {
      errors.push('CRITICAL: Only ' + r.messageInsights.length + ' insights remain after removing hallucinated messages (need 3+). Scenario must be regenerated.');
    }

    // Check DECODED requirement
    const hasDecoded = r.messageInsights.some(ins => ins.tag === 'DECODED');
    if (!hasDecoded) {
      errors.push('No DECODED insight found (at least 1 required)');
    }

    // Auto-remove greeting insights instead of failing
    const GREETING_WORDS = ['hi', 'hey', 'hello', 'sup', 'yo', 'hii', 'hiii', 'heyy', 'heyyy'];
    const beforeCount = r.messageInsights.length;
    r.messageInsights = r.messageInsights.filter(insight => {
      const lower = insight.message.toLowerCase().trim();
      if (GREETING_WORDS.includes(lower)) {
        errors.push('Auto-removed greeting insight: "' + insight.message + '" (non-critical)');
        return false;
      }
      return true;
    });
    if (beforeCount !== r.messageInsights.length) {
      errors.push('Removed ' + (beforeCount - r.messageInsights.length) + ' greeting insight(s) — ' + r.messageInsights.length + ' remaining');
    }
  }

  // --- Dynamic ---
  if (!r.dynamic || !r.dynamic.name) errors.push('Missing dynamic.name');
  if (!r.dynamic || !r.dynamic.whyThisHappens) errors.push('Missing dynamic.whyThisHappens');
  if (r.dynamic && (typeof r.dynamic.powerBalance !== 'number' || r.dynamic.powerBalance < 0 || r.dynamic.powerBalance > 100)) {
    errors.push('dynamic.powerBalance out of range: ' + (r.dynamic ? r.dynamic.powerBalance : 'undefined'));
  }
}

// Inject display metadata for content mode hero section
// These are pipeline-level fields, not AI output — stored in scenario JSON for Supabase
scenario.personDisplayName = scenario.chat ? scenario.chat.contactName : (randomName || 'Him');
scenario.personRelationshipStatus = randomRelStatus || null;

// Determine if we should pass the scenario through (allow minor errors)
const criticalErrors = errors.filter(e =>
  !e.includes('auto-fixed') &&
  !e.includes('out of range') &&
  !e.includes('auto-removed') &&
  !e.includes('non-critical') &&
  !e.includes('Auto-removed') &&
  !e.includes('hallucinated insight')
);
const valid = criticalErrors.length === 0;

return [{
  json: {
    valid,
    errors,
    scenario: scenario,
    errorCount: errors.length,
    criticalErrorCount: criticalErrors.length
  }
}];

// NODE: Build Copy Prompt
// Assembles the Gemini prompt for content copy generation
// Mode: Run Once for All Items

const { concept, vibe, scenarioName, bodyClipCount } = $('Select Concept').first().json;
const { scenario } = $('Validate Scenario').first().json;
const { captionTemplates, voTemplates, hookTexts, socialExamples, randomRelStatus, randomName, selectedContext } = $('Build Scenario Prompt').first().json;

// ============================================================
// OUTRO CATEGORY SELECTION (from Outro Examples pool)
// ============================================================

// Read outro examples from upstream Airtable node
let outroExamples = [];
try {
  outroExamples = $('Get Outro Examples').all().map(i => i.json);
} catch(e) {
  // Node might not exist yet — fall back to empty
}

// Parse outro_categories_json from concept (weights per category)
// Format: {"app_store": 30, "cta_lipsync": 35, "organic": 35}
let outroCategoryWeights = null;
if (concept.outro_categories_json) {
  try {
    outroCategoryWeights = typeof concept.outro_categories_json === 'string'
      ? JSON.parse(concept.outro_categories_json)
      : concept.outro_categories_json;
  } catch(e) { outroCategoryWeights = null; }
}

// Pick a category based on weights
let selectedOutroCategory = 'organic'; // default
let selectedOutroText = '';
let selectedOutroVO = '';

if (outroCategoryWeights && typeof outroCategoryWeights === 'object') {
  const categories = Object.entries(outroCategoryWeights).filter(([_, w]) => w > 0);
  if (categories.length > 0) {
    const totalWeight = categories.reduce((sum, [_, w]) => sum + w, 0);
    let rand = Math.random() * totalWeight;
    for (const [cat, w] of categories) {
      rand -= w;
      if (rand <= 0) { selectedOutroCategory = cat; break; }
    }
  }
}

// Pick a random active example from the selected category
if (outroExamples.length > 0) {
  const pool = outroExamples.filter(e => e.category === selectedOutroCategory && e.is_active !== false);
  if (pool.length > 0) {
    const picked = pool[Math.floor(Math.random() * pool.length)];
    selectedOutroText = picked.text || '';
    selectedOutroVO = picked.vo_text || picked.text || '';
  }
}

// ============================================================
// BODY CLIP SECTIONS (fixed order, first 2 always included)
// ============================================================

// Toxic score for display (inverted: 100 - health = toxicity)
const toxicScore = 100 - scenario.results.overallScore;
const r = scenario.results;

// Build section data with ACTUAL scenario content for each section
const ALL_BODY_SECTIONS = [
  {
    id: 'toxic_score',
    name: 'Toxic Score',
    description: 'Shows the toxicity score gauge animating to the final number.',
    data: 'Score: ' + toxicScore + '/100'
  },
  {
    id: 'soul_type',
    name: 'His Soul Type',
    description: 'Reveals his personality archetype card. The screen shows his Soul Type name, traits, and description.',
    data: 'Soul Type: ' + r.personSoulType
      + '\nTraits: ' + (r.personTraits || []).join(', ')
      + '\nDescription: ' + (r.personDescription || '')
  },
  {
    id: 'wtf_happening',
    name: 'What The Fuck Is Really Happening',
    description: 'Shows the 5 analysis cards: Intentions, Chemistry, Effort, Red Flags/Green Flags, Trajectory. Girl scrolls through the category breakdowns.',
    data: 'Intentions: ' + (r.categories && r.categories.intentions ? r.categories.intentions.description : '')
      + '\nChemistry: ' + (r.categories && r.categories.chemistry ? r.categories.chemistry.description : '')
      + '\nEffort: ' + (r.categories && r.categories.effort ? r.categories.effort.description : '')
      + '\nRed/Green Flags: ' + (r.categories && r.categories.redFlagsGreenFlags ? r.categories.redFlagsGreenFlags.description : '')
      + '\nTrajectory: ' + (r.categories && r.categories.trajectory ? r.categories.trajectory.description : '')
  },
  {
    id: 'between_the_lines',
    name: 'Between The Lines',
    description: 'Shows decoded message insights — specific chat messages highlighted with what they REALLY mean. Red flags, green flags, and decoded hidden meanings.',
    data: (r.messageInsights || []).map(ins => '[' + ins.tag + '] "' + ins.message + '" — ' + ins.title).join('\n')
  },
  {
    id: 'souls_together',
    name: 'Your Souls Together',
    description: 'Shows the dynamic card with both soul types combined. Reveals the relationship dynamic name, why it happens, and the power balance.',
    data: 'Dynamic: ' + (r.dynamic ? r.dynamic.name : '')
      + '\nSubtitle: ' + (r.dynamic ? r.dynamic.subtitle : '')
      + '\nWhy: ' + (r.dynamic ? r.dynamic.whyThisHappens : '')
